#!/usr/bin/env python3
import sys
import subprocess
import importlib
from pathlib import Path

# --- pytest auto-install ---
try:
    import pytest
except ImportError:
    print("pytest not found, installing...")
    subprocess.check_call([sys.executable, "-m", "pip", "install", "pytest"])
    pytest = importlib.import_module("pytest")

# --- directory config ---
TASK_DIR = Path(__file__).resolve().parent
PROJECT_ROOT = TASK_DIR.parent
WORKSPACE_DIR = Path(__file__).parent / "workspace"  # MANDATORY LINE — do not remove or rename


def _search_bases():
    """Where to look for agent output files."""
    return [
        Path(__file__).parent / "workspace",  # /home/user/workspace/workspace
        Path(__file__).parent,                # /home/user/workspace — where agent writes
        WORKSPACE_DIR,
        TASK_DIR,
    ]


def _find_snapshot():
    """Where to look for snapshots.json (written to ~ by the fetch script)."""
    for path in (
        Path.home() / "snapshots.json",                        # fetch script writes here
        Path(__file__).parent / "snapshots.json",
        Path(__file__).parent / "workspace" / "snapshots.json",
        TASK_DIR / "snapshots.json",
        TASK_DIR / "snapshot.json",
    ):
        if path.is_file():
            return path
    return None


def _find_memory_md():
    """Find memory.md (case-insensitive stem)."""
    for base in _search_bases():
        if not base.exists():
            continue
        for path in base.rglob("*.md"):
            try:
                if path.is_file() and path.stem.lower() == "memory":
                    return path.resolve()
            except OSError:
                continue
    return None


# --- tests go here ---


if __name__ == "__main__":
    pytest.main([str(Path(__file__).resolve()), "-rA", "--tb=short"])
